const { db } = require('../config/database');

class PatternAsset {
  constructor(data) {
    this.id = data.id;
    this.key = data.key;
    this.width = data.width;
    this.height = data.height;
    this.encoding = data.encoding;
    this.payload = data.payload;
    this.verified = data.verified;
    this.created_by = data.created_by;
    this.created_at = data.created_at;
    this.updated_at = data.updated_at;
    this.deleted_at = data.deleted_at;
  }

  // 创建图案资源
  static async create(patternData) {
    const { key, width, height, encoding, payload, created_by, verified = false } = patternData;
    
    // 验证尺寸限制 - 增大到64x64
    if (width > 64 || height > 64) {
      throw new Error('图案尺寸不能超过64x64');
    }
    
    // 验证编码格式
    if (!['rle', 'png_base64'].includes(encoding)) {
      throw new Error('不支持的编码格式');
    }
    
    // 验证payload
    if (encoding === 'rle') {
      if (!PatternAsset.validateRLEPayload(payload, width, height)) {
        throw new Error('RLE编码数据格式无效');
      }
    } else if (encoding === 'png_base64') {
      if (!PatternAsset.validatePNGBase64(payload)) {
        throw new Error('PNG base64数据格式无效');
      }
    }
    
    const [pattern] = await db('pattern_assets')
      .insert({
        key,
        width,
        height,
        encoding,
        payload,
        verified,
        created_by
      })
      .returning('*');
    
    return new PatternAsset(pattern);
  }

  // 根据ID获取图案
  static async getById(id) {
    const pattern = await db('pattern_assets')
      .where('id', id)
      .whereNull('deleted_at')
      .first();
    
    return pattern ? new PatternAsset(pattern) : null;
  }

  // 根据key获取图案
  static async getByKey(key) {
    const pattern = await db('pattern_assets')
      .where('key', key)
      .whereNull('deleted_at')
      .first();
    
    return pattern ? new PatternAsset(pattern) : null;
  }

  // 获取图案清单（用于客户端预加载）
  static async getManifest() {
    const patterns = await db('pattern_assets')
      .select('id', 'key', 'width', 'height', 'encoding', 'verified', 'payload')
      .whereNull('deleted_at')
      .orderBy('key');
    
    return patterns.map(pattern => ({
      id: pattern.id,
      key: pattern.key,
      width: pattern.width,
      height: pattern.height,
      encoding: pattern.encoding,
      verified: pattern.verified,
      hash: PatternAsset.generateHash(pattern.payload) // 用于缓存验证
    }));
  }

  // 获取已验证的图案（可用于商店）
  static async getVerifiedPatterns() {
    const patterns = await db('pattern_assets')
      .where('verified', true)
      .whereNull('deleted_at')
      .orderBy('key');
    
    return patterns.map(pattern => new PatternAsset(pattern));
  }

  // 验证RLE编码数据
  static validateRLEPayload(payload, width, height) {
    try {
      const data = JSON.parse(payload);
      if (!Array.isArray(data)) return false;
      
      let totalPixels = 0;
      for (const run of data) {
        if (typeof run.count !== 'number' || typeof run.color !== 'string') {
          return false;
        }
        totalPixels += run.count;
      }
      
      return totalPixels === width * height;
    } catch (error) {
      return false;
    }
  }

  // 验证PNG base64数据
  static validatePNGBase64(payload) {
    try {
      // 检查是否为有效的base64
      if (!/^[A-Za-z0-9+/]*={0,2}$/.test(payload)) {
        return false;
      }
      
      // 检查PNG文件头
      const buffer = Buffer.from(payload, 'base64');
      const pngHeader = Buffer.from([0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A]);
      
      return buffer.length >= 8 && buffer.subarray(0, 8).equals(pngHeader);
    } catch (error) {
      return false;
    }
  }

  // 生成数据哈希（用于缓存验证）
  static generateHash(data) {
    const crypto = require('crypto');
    return crypto.createHash('md5').update(data).digest('hex');
  }

  // 软删除图案
  async softDelete() {
    await db('pattern_assets')
      .where('id', this.id)
      .update({ deleted_at: db.fn.now() });
    
    this.deleted_at = new Date();
  }

  // 验证图案
  async verify() {
    await db('pattern_assets')
      .where('id', this.id)
      .update({ verified: true });
    
    this.verified = true;
  }

  // 更新图案
  async update(updateData) {
    const allowedFields = ['key', 'width', 'height', 'encoding', 'payload', 'verified'];
    const updateFields = {};
    
    for (const field of allowedFields) {
      if (updateData[field] !== undefined) {
        updateFields[field] = updateData[field];
      }
    }
    
    if (Object.keys(updateFields).length === 0) {
      return;
    }
    
    updateFields.updated_at = db.fn.now();
    
    await db('pattern_assets')
      .where('id', this.id)
      .update(updateFields);
    
    // 更新实例属性
    Object.assign(this, updateFields);
  }
}

module.exports = PatternAsset;
